Here are comprehensive pytest-style unit tests for the factorial function:

```python
import pytest
from your_module import factorial  # replace 'your_module' with the actual module name


class TestFactorialHappyPath:
    """Tests for typical, expected use cases."""

    def test_factorial_of_small_positive_integer(self):
        assert factorial(4) == 24

    def test_factorial_of_larger_positive_integer(self):
        assert factorial(6) == 720

    def test_factorial_of_two(self):
        assert factorial(2) == 2


class TestFactorialEdgeCases:
    """Tests for boundary and special cases."""

    def test_factorial_of_zero(self):
        assert factorial(0) == 1

    def test_factorial_of_one(self):
        assert factorial(1) == 1

    def test_factorial_of_large_number(self):
        # 10! = 3,628,800
        assert factorial(10) == 3_628_800


class TestFactorialErrorCases:
    """Tests for invalid inputs that should raise exceptions."""

    def test_negative_small_raises_value_error(self):
        with pytest.raises(ValueError, match='n must be non-negative'):
            factorial(-1)

    def test_negative_large_raises_value_error(self):
        with pytest.raises(ValueError, match='n must be non-negative'):
            factorial(-100)

    @pytest.mark.parametrize("invalid_input", [-5, -1, -10_000])
    def test_various_negative_inputs_raise_value_error(self, invalid_input):
        with pytest.raises(ValueError):
            factorial(invalid_input)
```

### Explanation of test coverage:

| Category | Tests | Rationale |
|----------|-------|-----------|
| **Happy path** | `4`, `6`, `2` | Typical small-to-medium inputs that exercise the recursive logic |
| **Edge cases** | `0`, `1`, `10` | Base cases (`0`, `1`) verify the early return; `10` tests stack depth |
| **Error cases** | `-1`, `-100` | Confirms `ValueError` is raised with the correct message |

The `@pytest.mark.parametrize` decorator in the last test demonstrates how to test multiple negative values concisely. Make sure to replace `'your_module'` with the actual name of the module containing your `factorial` function.
